    onAddToHome: (AppItem) -> Unit,
    onRemove: (AppItem, String) -> Unit,
    onSelect: () -> Unit
) {
    val context = LocalContext.current
            Card(
            shape = RoundedCornerShape(20.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xF21C1C1E)),
